import chess

class ChessEvaluator:
    def __init__(self):
        self.piece_values = {
            chess.PAWN: 1,
            chess.KNIGHT: 3,
            chess.BISHOP: 3,
            chess.ROOK: 5,
            chess.QUEEN: 9,
            chess.KING: 0  # King's value is not considered in material evaluation
        }

    def evaluate_material(self, board):
        white_material = 0
        black_material = 0

        for piece_type in self.piece_values:
            white_material += len(board.pieces(piece_type, chess.WHITE)) * self.piece_values[piece_type]
            black_material += len(board.pieces(piece_type, chess.BLACK)) * self.piece_values[piece_type]

        return white_material - black_material

    def evaluate_mobility(self, board):
        white_moves = len(list(board.legal_moves))
        board.turn = chess.BLACK
        black_moves = len(list(board.legal_moves))
        board.turn = chess.WHITE  # Reset turn to original

        return white_moves - black_moves

    def evaluate_control(self, board):
        white_control = 0
        black_control = 0

        for square in chess.SQUARES:
            attackers = board.attackers(chess.WHITE, square)
            defenders = board.attackers(chess.BLACK, square)

            if attackers:
                white_control += 1
            if defenders:
                black_control += 1

        return white_control - black_control

    def evaluate_checks(self, board):
        if board.is_check():
            return 1 if board.turn == chess.BLACK else -1
        return 0

    def evaluate(self, fen=None, board=None):
        if board is None:
            if fen is None:
                board = chess.Board()
            else:
                board = chess.Board(fen)

        material_score = self.evaluate_material(board)
        mobility_score = self.evaluate_mobility(board) * 0.1  # Mobility is less important than material
        control_score = self.evaluate_control(board) * 0.05  # Control is least important
        checks_score = self.evaluate_checks(board) * 0.5  # Checks are moderately important

        total_score = material_score + mobility_score + control_score + checks_score

        return total_score

    def get_evaluation_description(self, score):
        if score > 0:
            return f"White has an advantage of {abs(score):.2f}"
        elif score < 0:
            return f"Black has an advantage of {abs(score):.2f}"
        else:
            return "The position is balanced"

