            black_material += len(board.pieces(piece_type, chess.BLACK)) * self.piece_values[piece_type]

        return white_material - black_material

    def evaluate_controlled_squares(self, board):
        white_control = 0
        black_control = 0

        for square in chess.SQUARES:
            attackers_white = len(board.attackers(chess.WHITE, square))
            attackers_black = len(board.attackers(chess.BLACK, square))

            if attackers_white > attackers_black:
                white_control += 1
            elif attackers_black > attackers_white:
                black_control += 1

        return white_control - black_control

    def evaluate_mobility(self, board):
        white_moves = 0
        black_moves = 0

        for move in board.legal_moves:
            if board.turn == chess.WHITE:
                white_moves += 1
            else:
                black_moves += 1

        # Switch turn to count opponent's moves
        board.push(chess.Move.null())
        for move in board.legal_moves:
            if board.turn == chess.WHITE:
                white_moves += 1
            else:
                black_moves += 1
        board.pop()

        return white_moves - black_moves

    def evaluate_checks(self, board):
        white_checks = 0
        black_checks = 0

        if board.is_check():
            if board.turn == chess.WHITE:
                black_checks += 1
            else:
                white_checks += 1

        # Switch turn to check opponent's checks
        board.push(chess.Move.null())
        if board.is_check():
            if board.turn == chess.WHITE:
                black_checks += 1
            else:
                white_checks += 1
        board.pop()

        return white_checks - black_checks

    def evaluate(self, board):
        material = self.evaluate_material(board)
        control = self.evaluate_controlled_squares(board) * 0.1
        mobility = self.evaluate_mobility(board) * 0.05
        checks = self.evaluate_checks(board) * 0.5

